// Redefining the kernel logic as a function that processes a single block
template<typename T, int N>
void process_block_bcao(
  T *g_odata,
  const T *g_idata,
  int64_t bid)
{
  T temp[2*N];

  auto gi = g_idata + bid * N;
  auto go = g_odata + bid * N;

  // Simulate threads 0 to N/2 - 1
  // Since the operations for a specific 'd' are independent across 'thid', we can loop thid sequentially.

  // Initialization
  for (int thid = 0; thid < N/2; thid++) {
    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);
    temp[a + oa] = gi[a];
    temp[b + ob] = gi[b];
  }

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1)
  {
    // __syncthreads() equivalent: all previous steps done.
    // Execute step for all thid < d
    for (int thid = 0; thid < d; thid++) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  // Zeroing
  // if (thid == 0) temp[N-1+OFFSET(N-1)] = 0;
  // Only thid 0 does this.
  temp[N-1+OFFSET(N-1)] = 0; 

  for (int d = 1; d < N; d *= 2) 
  {
    offset >>= 1;
    // __syncthreads()
    for (int thid = 0; thid < d; thid++) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi += OFFSET(bi);
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }
  // __syncthreads()

  // Write output
  for (int thid = 0; thid < N/2; thid++) {
    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);
    go[a] = temp[a + oa];
    go[b] = temp[b + ob];
  }
}

template<typename T, int N>
void process_block(
  T *g_odata,
  const T *g_idata,
  int64_t bid)
{
  T temp[N];

  auto gi = g_idata + bid * N;
  auto go = g_odata + bid * N;

  // Initialization
  for (int thid = 0; thid < N/2; thid++) {
    temp[2*thid]   = gi[2*thid];
    temp[2*thid+1] = gi[2*thid+1];
  }

  int offset = 1;
  for (int d = N >> 1; d > 0; d >>= 1)
  {
    for (int thid = 0; thid < d; thid++) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  temp[N-1] = 0; 

  for (int d = 1; d < N; d *= 2) 
  {
    offset >>= 1;
    for (int thid = 0; thid < d; thid++) {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }

  for (int thid = 0; thid < N/2; thid++) {
    go[2*thid] = temp[2*thid];
    go[2*thid+1] = temp[2*thid+1];
  }
}

