void scan_bcao_kernel_impl(
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata)
{
  #pragma omp parallel for
  for (int64_t bid = 0; bid < nblocks; bid++)
  {
    auto gi = g_idata + bid * N;
    auto go = g_odata + bid * N;

    T temp[2*N];

    #pragma omp parallel num_threads(N/2) shared(temp, gi, go)
    {
      int thid = omp_get_thread_num();
      int a = thid;
      int b = a + (N/2);
      int oa = OFFSET(a);
      int ob = OFFSET(b);

      temp[a + oa] = gi[a];
      temp[b + ob] = gi[b];

      int offset = 1;
      for (int d = N >> 1; d > 0; d >>= 1)
      {
        #pragma omp barrier
        if (thid < d)
        {
          int ai = offset*(2*thid+1)-1;
          int bi = offset*(2*thid+2)-1;
          ai += OFFSET(ai);
          bi += OFFSET(bi);
          temp[bi] += temp[ai];
        }
        offset *= 2;
      }

      if (thid == 0) temp[N-1+OFFSET(N-1)] = 0; 
      for (int d = 1; d < N; d *= 2) 
      {
        offset >>= 1;
        #pragma omp barrier
        if (thid < d)
        {
          int ai = offset*(2*thid+1)-1;
          int bi = offset*(2*thid+2)-1;
          ai += OFFSET(ai);
          bi += OFFSET(bi);
          T t = temp[ai];
          temp[ai] = temp[bi];
          temp[bi] += t;
        }
      }
      #pragma omp barrier

      go[a] = temp[a + oa];
      go[b] = temp[b + ob];
    }
  }
}

