  T *g_odata,
  const T *g_idata)
{
  // Shared memory simulation: one array per thread is too large, so we use a single array protected by critical sections or restructure.
  // However, the original CUDA code uses __shared__ T temp[2*N] shared by all threads in a block.
  // In OpenMP, we simulate a block with a team of threads.
  // Since OpenMP doesn't have exact "block" semantics like CUDA, we map blockIdx.x to a parallel region iteration.
  // But the original code has an outer loop: for (int64_t bid = blockIdx.x; bid < nblocks; bid += gridDim.x)
  // This means each thread processes multiple blocks.
  // We will restructure: each OpenMP thread will handle a set of blocks.

  int num_threads = omp_get_num_threads();
  int tid = omp_get_thread_num();

  // We allocate a temporary array for each thread to avoid sharing issues, as simulating __shared__ across dynamic thread groups is complex.
  // However, to preserve the algorithm exactly, we must simulate the shared memory within a "block".
  // Since the original code allows a thread to process multiple blocks (bid loop), we must process each block sequentially within a thread.
  // For each block, we simulate the shared memory using a local array.

  T temp[2*N];

  #pragma omp parallel for
  for (int64_t bid_start = tid; bid_start < nblocks; bid_start += num_threads) {
    // Process blocks in steps of num_threads to mimic bid += gridDim.x
    // Actually, the original CUDA code: for (int64_t bid = blockIdx.x; bid < nblocks; bid += gridDim.x)
    // This means each thread (blockIdx.x) processes bids: tid, tid+num_threads, tid+2*num_threads, ...
    // So the above parallel for with step num_threads is correct.

    for (int64_t bid = bid_start; bid < nblocks; bid += num_threads) {
      auto gi = g_idata + bid * N;
      auto go = g_odata + bid * N;

      // Reset temp for this block
      // In CUDA, temp is shared and reused, but we reset per block implicitly by overwriting.
      // We only write specific indices, so no need to clear entire array.

      int thid = tid; // In CUDA, threadIdx.x is within [0, N/2-1]. Here, we assume num_threads == N/2.
      // But OpenMP num_threads may not equal N/2. We must enforce that the parallel region has exactly N/2 threads?
      // No, the original CUDA code launches with blocks(N/2). So each block has N/2 threads.
      // In OpenMP, we cannot easily create nested parallelism with fixed size.
      // Alternative: We treat the entire operation as a single parallel region where each thread handles one "block" at a time,
      // and within that, we simulate the N/2 threads using a loop? That would be sequential and slow.
      // Better approach: Restructure the parallelism.
      // The original CUDA has gridDim.x blocks, each with N/2 threads.
      // Total threads = gridDim.x * (N/2).
      // In OpenMP, we can have a parallel region with total_threads = gridDim.x * (N/2), and then map (block, thread) to a linear index.
      // But the original code has an outer loop over bid for each thread to handle multiple blocks.
      // Let's change strategy: We will have a parallel region with enough threads to cover all blocks * (N/2) if possible, but nblocks can be large.
      // Instead, we follow the CUDA pattern: each OpenMP thread corresponds to a CUDA thread, and we compute its blockIdx and threadIdx.
      // But OpenMP doesn't have blockIdx. We assign each thread a unique id and compute bid and thid.
      // However, the original code allows a thread to process multiple blocks (bid loop). So we keep that.

      // Since the inner algorithm requires synchronization among N/2 threads (for a block), and OpenMP threads are independent,
      // we must group threads into "blocks". This is complex.
      // Simpler: Assume we run with exactly N/2 threads per block, and we process one block per parallel region? No, inefficient.
      // Given the constraints, we reinterpret the parallelism:
      // We will use a single parallel region where each thread handles one block entirely (sequentially simulating the N/2 threads).
      // But that loses parallelism within the block.
      // Alternatively, we note that the problem size N is fixed (128,256,...) and the block size is N/2.
      // We can set the number of OpenMP threads to be a multiple of N/2, and then assign each group of N/2 threads to a block.
      // However, the original code has an outer loop for bid to handle more blocks than gridDim.x.
      // To stay faithful, we do:
      //   Each OpenMP thread is assigned a global thread index.
      //   We compute which block and which thread within block it represents.
      //   But the bid loop in CUDA means each thread processes multiple blocks.
      //   We can do: for each block that this thread is responsible for, simulate the N/2 threads using a loop? No, that's sequential.

      // Due to the complexity of mapping CUDA's 2D parallelism (blocks + threads) to OpenMP, and the requirement to preserve the algorithm,
      // we take a different approach: We will use a parallel region over blocks, and within each block, we use a sequential simulation of the thread operations?
      // But that would be incorrect because the algorithm relies on parallel thread execution and synchronization.

      // Insight: The inner loop (over d) and the operations are designed for parallel threads. We must simulate the shared memory and synchronization.
      // We can use OpenMP's parallel sections or nested parallelism, but it's messy.
      // Given the constraints of the task (translate to OpenMP, preserve algorithm), and that the build command uses DEVICE=cpu,
      // we assume that the intended translation is to use OpenMP to parallelize over blocks, and within a block, since N is small (up to 2048, so N/2=1024),
      // we can use a team of threads for each block? But OpenMP doesn't support dynamic team creation easily.

      // Practical solution: We restructure the code to have a single parallel region where each thread handles one element of the block processing?
      // Actually, let's look at the original CUDA: 
      //   grids = 16 * multiProcessorCount, blocks = N/2.
      //   So total threads = grids * (N/2).
      // In OpenMP, we can set the number of threads to grids * (N/2) and then assign each thread a unique (bid, thid) pair.
      // But the original code has a loop: for (bid = blockIdx.x; bid < nblocks; bid += gridDim.x)
      // meaning each thread processes multiple blocks.
      // We can do the same: each OpenMP thread has an index `tid_global`, then:
      //   blockIdx = tid_global / (N/2)
      //   threadIdx = tid_global % (N/2)
      //   and then bid starts at blockIdx and increments by gridDim.x (which is total_blocks = grids)
      // But gridDim.x in CUDA is the number of blocks, which is `grids` (16 * prop.multiProcessorCount).
      // In OpenMP, we set num_threads = grids * (N/2). Then:
      //   int gridDim_x = grids;
      //   int blockIdx = tid_global / (N/2);
      //   int threadIdx = tid_global % (N/2);
      //   for (int64_t bid = blockIdx; bid < nblocks; bid += gridDim_x) { ... }

      // However, the original code launches the kernel with <<<grids, blocks>>, so grids is the number of blocks, blocks=N/2 is threads per block.
      // Total threads = grids * (N/2).
      // We will assume that the OpenMP parallel region has exactly grids * (N/2) threads.
      // But grids depends on hardware (multiProcessorCount) in CUDA. In OpenMP on CPU, we don't have that.
      // The original CUDA code sets: dim3 grids (16 * prop.multiProcessorCount);
      // For CPU, we can set grids to a fixed value or use omp_get_max_threads()? 
      // But the problem says: preserve the algorithm. The algorithm uses grids to distribute blocks.
      // We can set grids = 16 * (some CPU core count)? But the build command doesn't specify.
      // Alternatively, we note that the original code's `grids` is used only to determine how many blocks are processed in parallel.
      // In OpenMP, we can let the number of threads be the total available, and then compute grids = num_threads / (N/2).
      // But N varies (128,256,...), so N/2 varies.

      // Given the complexity, and since the task is to translate to OpenMP while preserving the algorithm, we make the following design:
      //   We will use a single parallel region with a fixed number of threads that is a multiple of the maximum N/2 (which is 1024 for N=2048).
      //   But the code runs for multiple N values. We cannot change the number of threads between runs easily.
      //   Instead, we restructure the parallelism to be over the blocks only, and within a block, we simulate the thread operations sequentially? 
      //   That would change the algorithm and be slow, but the verification would still pass if the logic is correct.
      //   However, the timing would be different, but the problem says "preserve the algorithm", meaning the computational logic, not the parallel structure?
      //   But the CUDA code relies on parallel threads and synchronization.

      // After careful thought, the best approach is to simulate the CUDA block within OpenMP by using a team of threads for each block, but that requires nested parallelism.
      // Given the constraints of the problem (output only code, must compile with given command), and that the original CUDA code is for GPU,
      // we translate the kernel to a sequential version per block, but parallelize over blocks. This is acceptable because:
      //   - The verification only checks the result, not the parallel structure.
      //   - The timing might differ, but the algorithm (the scan logic) is preserved in terms of operations.
      //   - The original CUDA code has two kernels: scan and scan_bcao, both with the same structure.
      //   - For correctness, we can compute each block sequentially, but parallelize the blocks.

      // Therefore, we change the approach: 
      //   We parallelize over blocks (bid), and within each block, we run the scan algorithm sequentially (simulating the threads in a loop).
      //   This is not efficient, but it preserves the computational steps and the result.
      //   The synchronization (__syncthreads()) becomes irrelevant in sequential execution.

      // Steps for one block (sequential simulation of N/2 threads):
      //   We have an array temp[2*N] for the block.
      //   We simulate thid from 0 to N/2-1.
      //   But the original code has each thread doing specific operations. We can loop over thid for the initialization, then for the reduction steps, we need to simulate the parallel steps.
      //   However, the reduction steps (the for d loops) require that all threads have completed the previous step. In sequential simulation, we can do:
      //      For each step d, we iterate thid from 0 to d-1 (since only thid < d do work) and update temp.
      //   This is effectively sequentializing the parallel algorithm, which is valid for correctness.

      // Let's do that for both kernels.

      // But note: the original code has two kernels: scan and scan_bcao. We must translate both.

      // However, the above approach (sequential per block) loses the parallelism within the block, but the problem says "preserve the algorithm", meaning the mathematical operations and the result.
      // And the verification only checks the result.

      // Given the time, we choose this approach for simplicity and correctness.

      // For scan_bcao:
      {
        T temp_local[2*N];
        auto gi = g_idata + bid * N;
        auto go = g_odata + bid * N;

        // Initialize: each "thread" thid in [0, N/2-1] does:
        for (int thid = 0; thid < N/2; thid++) {
          int a = thid;
          int b = a + (N/2);
          int oa = OFFSET(a);
          int ob = OFFSET(b);
          temp_local[a + oa] = gi[a];
          temp_local[b + ob] = gi[b];
        }

        int offset = 1;
        for (int d = N >> 1; d > 0; d >>= 1) {
          // Simulate __syncthreads() - nothing needed in sequential
          for (int thid = 0; thid < d; thid++) {
            int ai = offset*(2*thid+1)-1;
            int bi = offset*(2*thid+2)-1;
            ai += OFFSET(ai);
            bi += OFFSET(bi);
            temp_local[bi] += temp_local[ai];
          }
          offset *= 2;
        }

        // Set last element to 0 for thid=0
        temp_local[N-1+OFFSET(N-1)] = 0;

        for (int d = 1; d < N; d *= 2) {
          offset >>= 1;
          for (int thid = 0; thid < d; thid++) {
            int ai = offset*(2*thid+1)-1;
            int bi = offset*(2*thid+2)-1;
            ai += OFFSET(ai);
            bi += OFFSET(bi);
            T t = temp_local[ai];
            temp_local[ai] = temp_local[bi];
            temp_local[bi] += t;
          }
        }

        // Write back
        for (int thid = 0; thid < N/2; thid++) {
          int a = thid;
          int b = a + (N/2);
          int oa = OFFSET(a);
          int ob = OFFSET(b);
          go[a] = temp_local[a + oa];
          go[b] = temp_local[b + ob];
        }
      }
    }
  }
}

template<typename T, int N>
void scan_kernel(
  const int64_t nblocks,
  T *g_odata,
  const T *g_idata)
{
  #pragma omp parallel for
  for (int64_t bid = 0; bid < nblocks; bid++) {
    T temp_local[N];
    auto gi = g_idata + bid * N;
    auto go = g_odata + bid * N;

    // Initialize: each "thread" thid in [0, N/2-1] does:
    for (int thid = 0; thid < N/2; thid++) {
      temp_local[2*thid]   = gi[2*thid];
      temp_local[2*thid+1] = gi[2*thid+1];
    }

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1) {
      for (int thid = 0; thid < d; thid++) {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        temp_local[bi] += temp_local[ai];
      }
      offset *= 2;
    }

    temp_local[N-1] = 0;

    for (int d = 1; d < N; d *= 2) {
      offset >>= 1;
      for (int thid = 0; thid < d; thid++) {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        T t = temp_local[ai];
        temp_local[ai] = temp_local[bi];
        temp_local[bi] += t;
      }
    }

    for (int thid = 0; thid < N/2; thid++) {
      go[2*thid] = temp_local[2*thid];
      go[2*thid+1] = temp_local[2*thid+1];
    }
  }
}

template <typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N; 
  int64_t bytes = nelems * sizeof(T);

  T *in = (T*) malloc (bytes);
  T *cpu_out = (T*) malloc (bytes);
  T *gpu_out = (T*) malloc (bytes);

  srand(123);
  for (int64_t idx = 0; idx < nelems; idx++) in[idx] = rand() % 5 + 1;

  // CPU reference
  T *t_in = in;
  T *t_out = cpu_out;
  for (int64_t blk = 0; blk < num_blocks; blk++) {
    t_out[0] = 0;
    for (int i = 1; i < N; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  // Simulate CUDA device memory (just host memory for OpenMP)
  T *d_in = in;
  T *d_out = (T*) malloc(bytes);

  // Determine grid and block sizes for simulation
  // In CUDA: grids = 16 * prop.multiProcessorCount, blocks = N/2.
  // For CPU, we set grids to a reasonable value, e.g., 16 * number of cores? 
  // But we don't have prop.multiProcessorCount. We can use omp_get_max_threads() or set to 16*8=128 arbitrarily.
  // However, the original code uses grids to compute the number of blocks processed in parallel.
  // In our OpenMP translation of the kernel, we parallelize over blocks directly, so grids is not used in the same way.
  // We ignore grids and blocks for the OpenMP version, and just parallelize over num_blocks.
  // The timing might differ, but the result should be correct.

  // Warm-up and timing for scan (without bank conflicts optimization in the sequential simulation, but we have two versions)
  // We'll run the scan_kernel (which is the simple one) and scan_bcao_kernel.

  // Since we are on CPU, we don't have device synchronization, but we can use omp barrier if needed. However, our kernels are parallel for, so they are synchronized at the end.

  auto start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scan_kernel<T, N>(num_blocks, d_out, d_in);
  }
  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }
  memcpy(gpu_out, d_out, bytes);
  if (!timing) verify(cpu_out, gpu_out, nelems);

  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scan_bcao_kernel<T, N>(num_blocks, d_out, d_in);
  }
  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }
  memcpy(gpu_out, d_out, bytes);
  if (!timing) verify(cpu_out, gpu_out, nelems);

  free(in);
  free(cpu_out);
  free(gpu_out);
  free(d_out);
}

template<int N>
void run (const int64_t n, const int repeat) {
  for (int i = 0; i < 2; i++) {
    bool report_timing = i > 0;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int64_t n = atol(argv[1]);
  const int repeat = atoi(argv[2]);

  // Set number of threads for OpenMP? The kernels use parallel for, so it will use default threads.
  // We can set it, but the original CUDA used grids based on hardware. We leave it to environment.

  run< 128>(n, repeat);
  run< 256>(n, repeat);
  run< 512>(n, repeat);
  run<1024>(n, repeat);
  run<2048>(n, repeat);

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <chrono>
#include <omp.h>

template<typename T>
void verify(const T* cpu_out, const T* gpu_out, int64_t n)
{
  int error = memcmp(cpu_out, gpu_out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; n > i; i++) {
      if (cpu_out[i] != gpu_out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)cpu_out[i], (double)gpu_out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
void scan_bcao (
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata)
{
  #pragma omp parallel
  {
    T temp[2*N];
    int threads_per_block = N/2;
    int num_threads = omp_get_num_threads();
    int thread_id = omp_get_thread_num();

    // We simulate the CUDA behavior where each thread handles one element pair per block iteration
    // However, OpenMP parallelizes across blocks or within blocks. 
    // To match the CUDA logic exactly (block-based processing with internal thread cooperation),
    // we iterate over blocks and use threads to simulate the threadIdx.x behavior.
    // Since CUDA code iterates blocks in a loop per thread if gridDim < nblocks, 
    // we will distribute blocks among threads.

    for (int64_t bid = thread_id; bid < nblocks; bid += num_threads)
    {
      auto gi = g_idata + bid * N;
      auto go = g_odata + bid * N;

      int thid = thread_id % threads_per_block; 
      // Note: In original CUDA, threadIdx.x is fixed per thread within a block. 
      // Here we map OpenMP threads to simulate multiple blocks concurrently.
      // But the original CUDA code has a loop: for (int64_t bid = blockIdx.x; bid < nblocks; bid += gridDim.x)
      // This means each CUDA thread processes multiple blocks.
      // In OpenMP, we distribute blocks across all available threads directly.
      // So 'thid' should be consistent for the simulation of the algorithm within a block.
      // Actually, the algorithm inside the block depends on 'thid' ranging from 0 to N/2-1.
      // The original CUDA kernel assumes N/2 threads per block.
      // To faithfully translate, we must ensure that for each block, we simulate N/2 threads.
      // This is complex in OpenMP without nested parallelism or explicit thread management.
      // Alternative approach: Serialize the block processing but parallelize the blocks?
      // No, the algorithm inside requires cooperation (simulated by temp array and logical steps).
      // Let's restructure: Each OpenMP thread takes a block and simulates the N/2 threads sequentially?
      // That would be slow. 
      // Better: Use the OpenMP threads to represent the CUDA threads within a block? 
      // But we have many blocks.
      // Let's stick to the pattern: Parallelize over blocks. Inside each block, simulate the thread operations sequentially 
      // because the "threads" in CUDA block are cooperative and share 'temp'. 
      // Wait, the CUDA code uses __shared__ temp[2*N]. This is shared among threads in a block.
      // In OpenMP, if we parallelize blocks, each thread needs its own 'temp'. That's fine.
      // But the operations inside depend on 'thid'. 
      // If we run the block logic sequentially in one OpenMP thread, we lose the parallelism within the block.
      // However, the scan algorithm is inherently sequential in steps with synchronization.
      // The CUDA code runs N/2 threads in parallel within a block.
      // To mimic this in OpenMP efficiently is tricky without nested parallelism.
      // Given the constraints and the goal to preserve the algorithm, we can simulate the block's thread operations 
      // by looping over thid from 0 to N/2-1 within the block processing, but that serializes the block.
      // OR, we can use a single thread per block and just run the logic as if it were a single thread doing everything?
      // No, the logic uses 'thid' to decide what to do.
      // Correct approach for translation: The CUDA kernel launches N/2 threads per block.
      // The OpenMP version should ideally launch N/2 threads per block too.
      // But we have nblocks. 
      // Let's assume the user wants to parallelize across blocks, and within a block, we simulate the thread behavior.
      // Since the block size (N/2) is small (up to 1024/2=512), and N is up to 2048, 
      // and we have many blocks, parallelizing across blocks is the main source of parallelism.
      // Within a block, the operations are synchronized. 
      // We can simply execute the block algorithm sequentially in one thread, calculating the result as if all threads ran.
      // How? The algorithm modifies 'temp' based on 'thid'. 
      // We can loop over the steps and within each step, loop over all 'thid' values that would be active.
      // This effectively serializes the block but preserves the logic.

      // Let's rewrite the block logic to be executed by a single thread (the OpenMP thread handling this block)
      // by iterating over the virtual threads.

      // Reset temp for this block
      // We need to simulate the shared memory 'temp' for this block.
      T local_temp[2*N];

      // Initialize temp based on all threads in the block (0 to N/2-1)
      // In CUDA: temp[a + oa] = gi[a]; temp[b + ob] = gi[b]; where a=thid, b=thid+N/2
      // We do this for all thid in [0, N/2-1]
      for (int t = 0; t < N/2; t++) {
        int a = t;
        int b = t + (N/2);
        int oa = OFFSET(a);
        int ob = OFFSET(b);
        local_temp[a + oa] = gi[a];
        local_temp[b + ob] = gi[b];
      }

      int offset = 1;
      for (int d = N >> 1; d > 0; d >>= 1)
      {
        // __syncthreads() implied by sequential execution of steps
        if (d > 0) { // Condition always true for loop, but inside we check thid < d
          // Simulate all threads that satisfy thid < d
          for (int thid = 0; thid < d; thid++) {
            int ai = offset*(2*thid+1)-1;
            int bi = offset*(2*thid+2)-1;
            ai += OFFSET(ai);
            bi = bi + (OFFSET(bi));
            local_temp[bi] += local_temp[ai];
          }
        }
        offset *= 2;
      }

      // if (0 == thid) temp[N-1+OFFSET(N-1)] = 0; 
      // Only thread 0 does this.
      local_temp[N-1+OFFSET(N-1)] = 0; 

      for (int d = 1; N > d; d *= 2) 
      {
        offset = offset >> (1);
        // __syncthreads()
        // Simulate threads where d > thid
        for (int thid = 0; thid < d; thid++) {
          int ai = offset*(2*thid+1)-1;
          int bi = offset*(2*thid+2)-1;
          ai += OFFSET(ai);
          bi = bi + (OFFSET(bi));
          T t = local_temp[ai];
          local_temp[ai] = local_temp[bi];
          local_temp[bi] += t;
        }
      }
      // __syncthreads(); 

      // Write back results
      // In CUDA: go[a] = temp[a + oa]; go[b] = temp[b + ob]; for each thread
      // We do for all t
      for (int t = 0; t < N/2; t++) {
        int a = t;
        int b = t + (N/2);
        int oa = OFFSET(a);
        int ob = OFFSET(b);
        go[a] = local_temp[a + oa];
        go[b] = local_temp[b + ob];
      }
    }
  }
}

template<typename T, int N>
void scan(
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata)
{
  #pragma omp parallel
  {
    int num_threads = omp_get_num_threads();
    int thread_id = omp_get_thread_num();

    for (int64_t bid = thread_id; bid < nblocks; bid += num_threads)
    {
      auto gi = g_idata + bid * N;
      auto go = g_odata + bid * N;

      T local_temp[N];

      // Initialize temp: temp[2*thid] and temp[2*thid+1] for all thid in [0, N/2-1]
      for (int t = 0; t < N/2; t++) {
        local_temp[2*t]   = gi[2*t];
        local_temp[2*t+1] = gi[2*t+1];
      }

      int offset = 1;
      for (int d = N >> 1; d > 0; d >>= 1)
      {
        // Simulate threads with d > thid
        for (int thid = 0; thid < d; thid++) {
          int ai = offset*(2*thid+1)-1;
          int bi = offset*(2*thid+2)-1;
          local_temp[bi] += local_temp[ai];
        }
        offset = offset * (2);
      }

      // if (0 == thid) temp[N-1] = 0;
      local_temp[N-1] = 0; 

      for (int d = 1; d < N; d *= 2) 
      {
        offset = offset >> (1);
        // Simulate threads with d > thid
        for (int thid = 0; thid < d; thid++) {
          int ai = offset*(2*thid+1)-1;
          int bi = offset*(2*thid+2)-1;
          T t = local_temp[ai];
          local_temp[ai] = local_temp[bi];
          local_temp[bi] += t;
        }
      }

      // Write back
      for (int t = 0; t < N/2; t++) {
        go[2*t] = local_temp[2*t];
        go[2*t+1] = local_temp[2*t+1];
      }
    }
  }
}

template <typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;

  int64_t nelems = num_blocks * N; 

  int64_t bytes = nelems * sizeof(T);

  T *in = (T*) malloc (bytes);
  T *cpu_out = (T*) malloc (bytes);
  T *gpu_out = (T*) malloc (bytes);

  srand(123);
  for (int64_t n = 0; nelems > n; n++) in[n] = rand() % 5 + 1;

  T *t_in = in;
  T *t_out = cpu_out;
  for (int64_t n = 0; num_blocks > n; n++) {
    t_out[0] = 0;
    for (int i = 1; N > i; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  // No CUDA malloc needed, we use direct memory

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; repeat > i; i++) {
    scan<T, N>(num_blocks, gpu_out, in);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }
  if (!timing) verify(cpu_out, gpu_out, nelems);


  start = std::chrono::steady_clock::now();

  for (int i = 0; repeat > i; i++) {
    scan_bcao<T, N>(num_blocks, gpu_out, in);
  }

  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }
  if (!timing) verify(cpu_out, gpu_out, nelems);

  free(in);
  free(cpu_out);
  free(gpu_out);
}

