template<typename T>
void verify(const T* cpu_out, const T* gpu_out, int64_t n)
{
  int error = memcmp(cpu_out, gpu_out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; n > i; i++) {
      if (gpu_out[i] != cpu_out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)cpu_out[i], (double)gpu_out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
void scan_bcao (
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata)
{
  #pragma omp parallel
  {
    T temp[2*N];
    int64_t num_threads = omp_get_num_threads();
    int64_t tid = omp_get_thread_num();

    for (int64_t bid = tid; nblocks > bid; bid += num_threads)
    {
      auto gi = g_idata + bid * N;
      auto go = g_odata + bid * N;

      int thid = 0; 
      // Simulate thread loop within single thread context for block logic
      // Since OpenMP parallel region distributes blocks, we simulate the intra-block scan sequentially
      // but using the algorithm logic. However, the original CUDA code uses N/2 threads.
      // To preserve exact algorithm behavior without actual intra-block parallelism (which is hard in OpenMP without nested parallelism overhead),
      // we will implement the scan logic sequentially for the block, as the "threads" in CUDA block are logically sequential steps in this translation
      // unless we use tasking or nested parallelism. Given the constraint to preserve algorithm and output, 
      // and that N is up to 2048, a sequential simulation of the block's thread logic is safest and correct.

      // Re-implementing the block logic sequentially for correctness in OpenMP CPU context
      // Step 1: Load
      for (int t = 0; t < N/2; t++) {
        int a = t;
        int b = a + (N/2);
        int oa = OFFSET(a);
        int ob = OFFSET(b);
        temp[a + oa] = gi[a];
        temp[b + ob] = gi[b];
      }

      // Step 2: Up-sweep
      int offset = 1;
      for (int d = N >> 1; 0 < d; d >>= 1)
      {
        if (d > 0) // Condition for some threads to act
        {
          // Simulate parallel step sequentially
          for (int thid_sim = 0; thid_sim < d; thid_sim++) {
            int ai = offset*(2*thid_sim+1)-1;
            int bi = offset*(2*thid_sim+2)-1;
            ai = ai + (OFFSET(ai));
            bi = bi + (OFFSET(bi));
            temp[bi] += temp[ai];
          }
        }
        offset = offset * (2);
      }

      // Step 3: Set last element to 0
      temp[N-1+OFFSET(N-1)] = 0; 

      // Step 4: Down-sweep
      for (int d = 1; N > d; d *= 2) 
      {
        offset = offset >> (1);
        if (d > 0)
        {
          for (int thid_sim = 0; thid_sim < d; thid_sim++) {
            int ai = offset*(2*thid_sim+1)-1;
            int bi = offset*(2*thid_sim+2)-1;
            ai = ai + (OFFSET(ai));
            bi = bi + (OFFSET(bi));
            T t = temp[ai];
            temp[ai] = temp[bi];
            temp[bi] += t;
          }
        }
      }

      // Step 5: Store
      for (int t = 0; t < N/2; t++) {
        int a = t;
        int b = a + (N/2);
        int oa = OFFSET(a);
        int ob = OFFSET(b);
        go[a] = temp[a + oa];
        go[b] = temp[b + ob];
      }
    }
  }
}

template<typename T, int N>
void scan(
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata)
{
  #pragma omp parallel
  {
    T temp[N];
    int64_t num_threads = omp_get_num_threads();
    int64_t tid = omp_get_thread_num();

    for (int64_t bid = tid; nblocks > bid; bid += num_threads)
    {
      auto gi = g_idata + bid * N;
      auto go = g_odata + bid * N;

      // Load
      for (int t = 0; t < N/2; t++) {
        temp[2*t]   = gi[2*t];
        temp[2*t+1] = gi[2*t+1];
      }

      // Up-sweep
      int offset = 1;
      for (int d = N >> 1; 0 < d; d >>= 1)
      {
        if (d > 0) {
          for (int thid_sim = 0; thid_sim < d; thid_sim++) {
            int ai = offset*(2*thid_sim+1)-1;
            int bi = offset*(2*thid_sim+2)-1;
            temp[bi] += temp[ai];
          }
        }
        offset = offset * (2);
      }

      // Set last
      temp[N-1] = 0; 

      // Down-sweep
      for (int d = 1; N > d; d *= 2) 
      {
        offset = offset >> (1);
        if (d > 0) {
          for (int thid_sim = 0; thid_sim < d; thid_sim++) {
            int ai = offset*(2*thid_sim+1)-1;
            int bi = offset*(2*thid_sim+2)-1;
            T t = temp[ai];
            temp[ai] = temp[bi];
            temp[bi] += t;
          }
        }
      }

      // Store
      for (int t = 0; t < N/2; t++) {
        go[2*t] = temp[2*t];
        go[2*t+1] = temp[2*t+1];
      }
    }
  }
}

template <typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;

  int64_t nelems = num_blocks * N; 

  int64_t bytes = nelems * sizeof(T);

  T *in = (T*) malloc (bytes);
  T *cpu_out = (T*) malloc (bytes);
  T *gpu_out = (T*) malloc (bytes);

  srand(123);
  for (int64_t idx = 0; nelems > idx; idx++) in[idx] = rand() % 5 + 1;

  T *t_in = in;
  T *t_out = cpu_out;
  for (int64_t b = 0; num_blocks > b; b++) {
    t_out[0] = 0;
    for (int i = 1; N > i; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  T *d_in = in;
  T *d_out = gpu_out; // Reuse gpu_out buffer for "device" simulation

  // Determine thread count similar to CUDA grid calculation
  // CUDA: grids = 16 * multiProcessorCount. 
  // On CPU, we let OpenMP decide or set a reasonable default. 
  // The logic inside scan uses omp_get_num_threads() to distribute blocks.

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; repeat > i; i++) {
    scan<T, N>(num_blocks, d_out, d_in);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }

  // Data is already in gpu_out (d_out)
  if (!timing) verify(cpu_out, gpu_out, nelems);


  start = std::chrono::steady_clock::now();

  for (int i = 0; repeat > i; i++) {
    scan_bcao<T, N>(num_blocks, d_out, d_in);
  }

  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }
  if (!timing) verify(cpu_out, gpu_out, nelems);

  free(in);
  free(cpu_out);
  free(gpu_out);
}

template<int N>
void run (const int64_t n, const int repeat) {
  for (int i = 0; 2 > i; i++) {
    bool report_timing = 0 < i;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
