#define RADIUS 7
#define BLOCK_SIZE 256

void stencil_1d(const int *in, int *out, int length) {
    int num_blocks = length / BLOCK_SIZE;

    #pragma omp parallel for schedule(static, 1)
    for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
        int temp[BLOCK_SIZE + 2 * RADIUS];
        int gindex_base = block_idx * BLOCK_SIZE;

        // Load main block data into shared temp array (simulated as local array)
        // lindex = threadIdx.x + RADIUS
        for (int t = 0; t < BLOCK_SIZE; t++) {
            int gindex = gindex_base + t;
            int lindex = t + RADIUS;
            temp[lindex] = in[gindex];
        }

        // Handle boundary loads for threads where threadIdx.x < RADIUS
        // In the CUDA code, these specific threads load the left and right padding
        // We replicate this logic sequentially for the block
        for (int t = 0; t < RADIUS; t++) {
            int gindex = gindex_base + t;
            int lindex = t + RADIUS;

            // Left side: temp[lindex - RADIUS]
            int left_gindex = gindex - RADIUS;
            temp[lindex - RADIUS] = (left_gindex < 0) ? 0 : in[left_gindex];

            // Right side: temp[lindex + BLOCK_SIZE]
            int right_gindex = gindex + BLOCK_SIZE;
            // The original CUDA code accesses in[gindex + BLOCK_SIZE]. 
            // Since 'in' is allocated with pad_size = (length + RADIUS), 
            // and gindex + BLOCK_SIZE can be up to (num_blocks-1)*BLOCK_SIZE + BLOCK_SIZE = length.
            // If length < pad_size, this access is valid.
            temp[lindex + BLOCK_SIZE] = in[right_gindex];
        }

        // Compute stencil
        for (int t = 0; t < BLOCK_SIZE; t++) {
            int gindex = gindex_base + t;
            int lindex = t + RADIUS;
            int result = 0;
            for (int offset = -RADIUS; offset <= RADIUS; offset++) {
                result += temp[lindex + offset];
            }
            out[gindex] = result;
        }
    }
}

